1	import crypto from 'crypto';
2	import { config } from '../config.js';
3	
4	function getKey() {
5	  const raw = config.encryption.aes256KeyHex || '';
6	  if (/^[a-fA-F0-9]{64}$/.test(raw)) {
7	    return Buffer.from(raw, 'hex');
8	  }
9	  // deterministic fallback for local offline bootstrap only
10	  return crypto.createHash('sha256').update(raw || 'roadsafe-dev-key').digest();
11	}
12	
13	export function encryptText(plainText) {
14	  const iv = crypto.randomBytes(12);
15	  const key = getKey();
16	  const cipher = crypto.createCipheriv('aes-256-gcm', key, iv);
17	  const encrypted = Buffer.concat([cipher.update(String(plainText), 'utf8'), cipher.final()]);
18	  const tag = cipher.getAuthTag();
19	  return Buffer.concat([iv, tag, encrypted]).toString('base64');
20	}
21	
22	export function decryptText(encoded) {
23	  const payload = Buffer.from(String(encoded), 'base64');
24	  const iv = payload.subarray(0, 12);
25	  const tag = payload.subarray(12, 28);
26	  const data = payload.subarray(28);
27	  const key = getKey();
28	  const decipher = crypto.createDecipheriv('aes-256-gcm', key, iv);
29	  decipher.setAuthTag(tag);
30	  return Buffer.concat([decipher.update(data), decipher.final()]).toString('utf8');
31	}
