7	const MAX_FILE_BYTES = 50 * 1024 * 1024;
8	const ALLOWED_MIME = new Set(['application/pdf', 'text/plain', 'text/csv', 'image/png', 'image/jpeg']);
9	const ALLOWED_EXT = new Set(['.pdf', '.txt', '.csv', '.png', '.jpg', '.jpeg']);
10	
11	function hashContent(buffer) {
12	  return crypto.createHash('sha256').update(buffer).digest('hex');
13	}
14	
15	function scanSensitive(buffer) {
16	  const text = buffer.toString('utf8');
17	  for (const rule of config.sensitiveContent.regexRules) {
18	    try {
19	      const regex = new RegExp(rule.pattern, 'gi');
20	      if (regex.test(text)) return rule.name;
21	    } catch {
22	      // Skip invalid runtime-configured expressions instead of crashing file governance.
23	    }
24	  }
25	
26	  const lowered = text.toLowerCase();
27	  for (const term of config.sensitiveContent.dictionaryTerms) {
28	    if (lowered.includes(String(term).toLowerCase())) {
29	      return `dictionary:${term}`;
30	    }
31	  }
32	  return null;
33	}
