35	export async function findAuthorizedFileDownload({ fileId, actor }) {
36	  const rows = await query(
37	    `SELECT id, uploaded_by, storage_path, file_name, mime_type, location_code, department_code
38	     FROM files
39	     WHERE id = ?`,
40	    [fileId]
41	  );
42	
43	  if (!rows.length) return null;
44	  const file = rows[0];
45	  if (actor.role !== 'Administrator') {
46	    if (
47	      file.location_code !== actor.locationCode ||
48	      file.department_code !== actor.departmentCode
49	    ) {
50	      return null;
51	    }
52	  }
53	
54	  if (!fs.existsSync(file.storage_path)) {
55	    throw new Error('Stored file missing on disk');
56	  }
57	
58	  return file;
59	}
