61	export async function validateAndIngestFile({
62	  uploaderId,
63	  locationCode,
64	  departmentCode,
65	  sourcePath,
66	  mimeType,
67	  linkedTable,
68	  linkedRecordId
69	}) {
70	  const resolved = path.resolve(sourcePath);
71	  if (!fs.existsSync(resolved)) throw new Error('File not found');
72	
73	  const stat = fs.statSync(resolved);
74	  if (stat.size > MAX_FILE_BYTES) {
75	    throw new Error('File exceeds 50MB limit');
76	  }
77	
78	  const ext = path.extname(resolved).toLowerCase();
79	  if (!ALLOWED_EXT.has(ext)) {
80	    throw new Error('Blocked file extension');
81	  }
82	
83	  if (mimeType && !ALLOWED_MIME.has(mimeType)) {
84	    throw new Error('Blocked MIME type');
85	  }
86	
87	  const buffer = fs.readFileSync(resolved);
88	  const checksum = hashContent(buffer);
89	
90	  const blocked = await query('SELECT id FROM blocked_file_hashes WHERE checksum_sha256 = ?', [checksum]);
91	  if (blocked.length) {
92	    throw new Error('File hash is blocked by governance policy');
93	  }
94	
95	  await query(
96	    `INSERT INTO files
97	      (uploaded_by, storage_path, file_name, mime_type, file_size_bytes, checksum_sha256, linked_table, linked_record_id, location_code, department_code)
98	     VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
99	    [
100	      uploaderId,
101	      resolved,
102	      path.basename(resolved),
103	      mimeType || null,
104	      stat.size,
105	      checksum,
106	      linkedTable || null,
107	      linkedRecordId || null,
108	      locationCode,
109	      departmentCode
110	    ]
111	  );
112	
113	  const rows = await query('SELECT LAST_INSERT_ID() AS id');
114	  const fileId = rows[0].id;
115	
116	  const sensitiveMatch = scanSensitive(buffer);
117	  if (sensitiveMatch) {
118	    await query(
119	      'INSERT INTO file_quarantine (file_id, reason, matched_pattern) VALUES (?, ?, ?)',
120	      [fileId, 'Sensitive content detected', sensitiveMatch]
121	    );
122	  }
123	
124	  return {
125	    fileId,
126	    checksum,
127	    quarantined: Boolean(sensitiveMatch),
128	    sensitivePattern: sensitiveMatch
129	  };
130	}
