9	function parseCsvList(value) {
10	  return String(value || '')
11	    .split(',')
12	    .map((item) => item.trim())
13	    .filter(Boolean);
14	}
15	
16	function parseRegexRuleList(value) {
17	  return parseCsvList(value).map((entry, index) => {
18	    const separator = entry.lastIndexOf('::');
19	    const name = separator >= 0 ? entry.slice(0, separator).trim() : `rule_${index + 1}`;
20	    const pattern = separator >= 0 ? entry.slice(separator + 2).trim() : entry;
21	    return { name, pattern };
22	  });
23	}
