{"replace_all": false, "file_path": "/home/eren/Documents/task4/Vehicle Inspection/repo/backend/src/services/retentionService.js", "old_string": "export async function createAccountClosureRequest(userId) {
  await query(
    `INSERT INTO account_closure_requests (user_id, due_by, status)
     VALUES (?, DATE_ADD(UTC_TIMESTAMP(), INTERVAL ? DAY), 'pending')`,
    [userId, ACCOUNT_CLOSURE_DAYS]
  );
  const rows = await query('SELECT LAST_INSERT_ID() AS id');
  return rows[0].id;
}", "new_string": "export async function createAccountClosureRequest(userId) {
  const existing = await query(
    `SELECT id FROM account_closure_requests WHERE user_id = ? AND status = 'pending' LIMIT 1`,
    [userId]
  );
  if (existing.length) return existing[0].id;

  await query(
    `INSERT INTO account_closure_requests (user_id, due_by, status)
     VALUES (?, DATE_ADD(UTC_TIMESTAMP(), INTERVAL ? DAY), 'pending')`,
    [userId, ACCOUNT_CLOSURE_DAYS]
  );
  const rows = await query('SELECT LAST_INSERT_ID() AS id');
  return rows[0].id;
}"}

